private static String[] concat(String first, String... others) {
    if (others.length == 0) {
      return new String[] { first };
    } else {
      String[] result = new String[others.length + 1];
      result[0] = first;
      System.arraycopy(others, 0, result, 1, others.length);
      return result;
    }
  }
